# There's a significant shift in the metrics around commit 190 (7c82ea8c1977857debaf29ae0156094e08096abe), which
# includes an update to Rust 1.87.
SPLIT_AT_INDEXES = [190]

# @formatter:on


def stability_metrics(x: np.ndarray):
    """Global stability metrics for a time series."""
    diffs = np.diff(x)
    abs_diffs = np.abs(diffs)

    mean = float(np.mean(x))

    standard_deviation = float(np.std(x))
    median_absolute_deviation = float(np.mean(np.abs(x - mean)))

    first_difference_standard_deviation = float(np.std(diffs))
    first_difference_median_absolute_deviation = float(np.mean(abs_diffs))

    within_1pct = float(np.mean(abs_diffs <= 0.01 * x[:-1]))
    within_2_5pct = float(np.mean(abs_diffs <= 0.025 * x[:-1]))
    within_5pct = float(np.mean(abs_diffs <= 0.05 * x[:-1]))

    return {
        "mean": mean,
        "rel_range": (float(np.max(x)) - float(np.min(x))) / mean,
        "rel_std": standard_deviation / mean,
        "rel_mad": median_absolute_deviation / mean,
        "rel_fd_std": first_difference_standard_deviation / mean,
        "rel_fd_mad": first_difference_median_absolute_deviation / mean,
        "within_1pct": within_1pct,
        "within_2.5pct": within_2_5pct,
        "within_5pct": within_5pct,
    }


def zero_change_metrics(x: np.ndarray, changed: np.ndarray):
    """
    Metrics only for commits where 'changed == 0', comparing to previous row.
    """
    idx = np.where(changed == 0)[0]
    idx = idx[idx > 0]  # need a previous sample

    prev = x[idx - 1]
    cur = x[idx]
    adiff = np.abs(cur - prev)
    rdiff = adiff / np.abs(prev)

    return {
        "zc_rel_mean": float(np.mean(rdiff)),
        "zc_within_1pct": float(np.mean(rdiff <= 0.01)),
    }


def analyse_range(start_index: int, end_index: int):
    print(f"Commits {start_index}..{end_index}")
    series = {
        "Without RUSTC_WRAPPER, no LTO": WITHOUT_RUSTC_WRAPPER_NO_LTO,
        "With RUSTC_WRAPPER, no LTO": WITH_RUSTC_WRAPPER_NO_LTO,
        "With RUSTC_WRAPPER, thin LTO": WITH_RUSTC_WRAPPER_THIN_LTO,
        "With RUSTC_WRAPPER, fat LTO": WITH_RUSTC_WRAPPER_FAT_LTO,
    }

    changes = np.array(SOURCE_FILES_CHANGED_PER_COMMIT[start_index:end_index])

    results = {}
    metrics_order = []

    # Collect all metrics
    for config, data in series.items():
        data = np.array(data[start_index:end_index])
        base = stability_metrics(data)
        zc = zero_change_metrics(data, changes)

        combined = {**base, **zc}
        results[config] = combined

        if not metrics_order:
            metrics_order = list(combined.keys())

    # Print Table
    configs = list(series.keys())
    col_w = 32
    metric_w = 16

    header = f"{'Metric':<{metric_w}} | " + " | ".join(f"{c:>{col_w}}" for c in configs)
    print(header)
    print("-" * len(header))

    for k in metrics_order:
        row_vals = []
        for c in configs:
            val = results[c][k]
            if "within" in k or "rel" in k:
                row_vals.append(f"{val * 100:>{col_w - 1}.2f}%")
            else:
                row_vals.append(f"{val:>{col_w}.1f}")

        print(f"{k:<{metric_w}} | " + " | ".join(row_vals))
    print()


def main():
    start_index = 0
    for split_at in SPLIT_AT_INDEXES:
        analyse_range(start_index, split_at)
        start_index = split_at
    analyse_range(start_index, len(SOURCE_FILES_CHANGED_PER_COMMIT))


if __name__ == "__main__":
    main()
